import{_ as o,C as n,o as d,c as r,ai as a,E as i,w as s,a as l}from"./chunks/framework.BH_J6TYN.js";const q=JSON.parse('{"title":"Panel de administración","description":"El dashboard flotante con 7 tabs para gestionar todo tu negocio","frontmatter":{"title":"Panel de administración","description":"El dashboard flotante con 7 tabs para gestionar todo tu negocio"},"headers":[],"relativePath":"studio/panel-administracion.md","filePath":"studio/panel-administracion.md"}'),c={name:"studio/panel-administracion.md"};function u(p,e,b,h,m,g){const t=n("Note");return d(),r("div",null,[e[1]||(e[1]=a('<h2 id="¿que-es" tabindex="-1">¿Qué es? <a class="header-anchor" href="#¿que-es" aria-label="Permalink to &quot;¿Qué es?&quot;">​</a></h2><p>El panel de administración es el dashboard flotante que aparece sobre tu página web. Desde ahí controlas absolutamente todo: información del negocio, productos, servicios, colores, medios de pago, y más.</p><p>No es una página separada — se activa <strong>encima</strong> de tu página con un gesto o atajo de teclado.</p><h2 id="¿donde-lo-encuentro" tabindex="-1">¿Dónde lo encuentro? <a class="header-anchor" href="#¿donde-lo-encuentro" aria-label="Permalink to &quot;¿Dónde lo encuentro?&quot;">​</a></h2><p>Desde tu página publicada (<code>tunegocio.syntiweb.com</code>):</p><ul><li><strong>Escritorio:</strong> Presiona <strong>Alt+S</strong></li><li><strong>Móvil:</strong> Mantén presionado el logo de tu negocio durante <strong>3 segundos</strong></li></ul><p>Se te pedirá un <strong>PIN de 4 dígitos</strong> para entrar.</p><h2 id="los-7-tabs-del-panel" tabindex="-1">Los 7 tabs del panel <a class="header-anchor" href="#los-7-tabs-del-panel" aria-label="Permalink to &quot;Los 7 tabs del panel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>Tab</th><th>Qué se configura</th></tr></thead><tbody><tr><td>1</td><td><strong>Tu Información</strong></td><td>Datos del negocio, horario, redes sociales</td></tr><tr><td>2</td><td><strong>Qué Vendes</strong></td><td>Productos y servicios (agregar, editar, eliminar)</td></tr><tr><td>3</td><td><strong>Cómo Se Ve</strong></td><td>Tema visual, paleta de colores</td></tr><tr><td>4</td><td><strong>Tu Mensaje</strong></td><td>Orden de secciones, testimonios, FAQ, sucursales, CTA</td></tr><tr><td>5</td><td><strong>Pulso del Negocio</strong></td><td>Analítica y estadísticas</td></tr><tr><td>6</td><td><strong>Visual</strong></td><td>Variantes de secciones y efectos visuales</td></tr><tr><td>7</td><td><strong>Configuración</strong></td><td>Medios de pago, moneda, PIN, información del plan</td></tr></tbody></table><h2 id="encabezado-del-panel" tabindex="-1">Encabezado del panel <a class="header-anchor" href="#encabezado-del-panel" aria-label="Permalink to &quot;Encabezado del panel&quot;">​</a></h2><p>En la parte superior siempre verás:</p><table tabindex="0"><thead><tr><th>Elemento</th><th>Descripción</th></tr></thead><tbody><tr><td>Logo + nombre del negocio</td><td>Identidad visual</td></tr><tr><td>Punto de estado</td><td>🟢 En línea / 🔴 Fuera de línea</td></tr><tr><td>Badge de plan</td><td>Tu plan actual (Oportunidad/Crecimiento/Visión)</td></tr><tr><td>Tasa del dólar</td><td>Bs. XX.XX (tasa BCV actualizada)</td></tr><tr><td>Botón <strong>&quot;Ver sitio&quot;</strong></td><td>Abre tu página en otra pestaña</td></tr></tbody></table><h2 id="¿que-no-hace" tabindex="-1">¿Qué NO hace? <a class="header-anchor" href="#¿que-no-hace" aria-label="Permalink to &quot;¿Qué NO hace?&quot;">​</a></h2><ul><li>No tiene versión separada en otra URL — solo existe encima de tu página</li><li>No permite editar el subdominio — ese se fijó en el asistente</li><li>No procesa pagos ni ventas</li><li>No tiene sección de facturación</li><li>No tiene chat en vivo con clientes</li></ul><h2 id="disponibilidad-por-plan" tabindex="-1">Disponibilidad por plan <a class="header-anchor" href="#disponibilidad-por-plan" aria-label="Permalink to &quot;Disponibilidad por plan&quot;">​</a></h2><p>El panel está disponible en <strong>todos los planes</strong>. Algunos tabs muestran funciones bloqueadas según tu plan:</p><table tabindex="0"><thead><tr><th>Plan</th><th>Restricciones</th></tr></thead><tbody><tr><td>Oportunidad</td><td>Secciones Acerca de, Testimonios, FAQ, Sucursales bloqueadas</td></tr><tr><td>Crecimiento</td><td>FAQ y Sucursales bloqueadas</td></tr><tr><td>Visión</td><td>Sin restricciones</td></tr></tbody></table>',17)),i(t,null,{default:s(()=>[...e[0]||(e[0]=[l(" Las secciones bloqueadas por plan se muestran con un ícono de candado 🔒 y un mensaje indicando qué plan necesitas para desbloquearlas. ",-1)])]),_:1}),e[2]||(e[2]=a('<h2 id="ejemplo-practico" tabindex="-1">Ejemplo práctico <a class="header-anchor" href="#ejemplo-practico" aria-label="Permalink to &quot;Ejemplo práctico&quot;">​</a></h2><h3 id="caso-pedro-administra-su-barberia-desde-el-celular" tabindex="-1">Caso: Pedro administra su barbería desde el celular <a class="header-anchor" href="#caso-pedro-administra-su-barberia-desde-el-celular" aria-label="Permalink to &quot;Caso: Pedro administra su barbería desde el celular&quot;">​</a></h3><ol><li>Abre <code>elcorte.syntiweb.com</code> en el navegador de su celular</li><li>Mantiene presionado el logo de su barbería 3 segundos</li><li>Aparece el campo de PIN → escribe su PIN</li><li>Se abre el panel flotante</li><li>Va a <strong>Qué Vendes</strong> → agrega un nuevo producto &quot;Aceite de barba&quot; a REF 8</li><li>Va a <strong>Cómo Se Ve</strong> → cambia la paleta de &quot;Default&quot; a &quot;Barber Clásico&quot;</li><li>Cierra el panel → su página ya muestra los cambios</li></ol><h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/studio/panel-flotante.html">Panel flotante</a> — Cómo activar y usar el panel desde cualquier dispositivo</li><li><a href="/studio/seccion-info.html">Tu Información</a> — Primer tab: datos del negocio</li><li><a href="/studio/seccion-config.html">Configuración</a> — Último tab: medios de pago, moneda, PIN</li></ul>',5))])}const _=o(c,[["render",u]]);export{q as __pageData,_ as default};
